     1→const SARVAM_TTS_URL = 'https://api.sarvam.ai/text-to-speech/stream';
     2→const DEFAULT_TTS_OPTIONS = {
     3→  target_language_code: 'en-IN',
     4→  model: 'bulbul:v3',
     5→  speaker: 'manan',
     6→  pace: 1.1,
     7→  speech_sample_rate: 22050,
     8→  output_audio_codec: 'mp3',
     9→};
    10→
    11→export default async function handler(req, res) {
    12→  if (req.method !== 'POST') {
    13→    return res.status(405).json({ error: 'Method not allowed' });
    14→  }
    15→
    16→  const apiKey = process.env.SARVAM_API_KEY;
    17→  if (!apiKey) {
    18→    return res.status(500).json({ error: 'Sarvam API key not configured' });
    19→  }
    20→
    21→  const text = typeof req.body?.text === 'string' ? req.body.text.trim() : '';
    22→  if (!text) {
    23→    return res.status(400).json({ error: 'Text is required' });
    24→  }
    25→
    26→  if (text.length > 2500) {
    27→    return res.status(400).json({ error: 'Text exceeds Sarvam limit of 2500 characters' });
    28→  }
    29→
    30→  try {
    31→    const response = await fetch(SARVAM_TTS_URL, {
    32→      method: 'POST',
    33→      headers: {
    34→        'api-subscription-key': apiKey,
    35→        'Content-Type': 'application/json',
    36→      },
    37→      body: JSON.stringify({
    38→        text,
    39→        ...DEFAULT_TTS_OPTIONS,
    40→      }),
    41→    });
    42→
    43→    if (!response.ok) {
    44→      const err = await response.json().catch(() => ({}));
    45→      console.error('Sarvam TTS error:', err);
    46→      return res.status(response.status).json({
    47→        error: err.error?.message || err.message || 'Sarvam TTS error',
    48→      });
    49→    }
    50→
    51→    const audioBuffer = Buffer.from(await response.arrayBuffer());
    52→    if (!audioBuffer.length) {
    53→      return res.status(500).json({ error: 'Empty audio response from Sarvam' });
    54→    }
    55→
    56→    res.setHeader('Content-Type', response.headers.get('content-type') || 'audio/mpeg');
    57→    res.setHeader('Cache-Control', 'no-store');
    58→    return res.status(200).send(audioBuffer);
    59→  } catch (err) {
    60→    console.error('TTS handler error:', err);
    61→    return res.status(500).json({ error: 'Internal server error' });
    62→  }
    63→}
    64→

